package com.google.gson.internal;
import com.google.gson.ExclusionStrategy;
import com.google.gson.FieldAttributes;
import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.TypeAdapterFactory;
import com.google.gson.annotations.Expose;
import com.google.gson.reflect.TypeToken;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.Modifier;
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.annotations.Since;
import com.google.gson.annotations.Until;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.annotation.Annotation;
import java.lang.reflect.Method;

class ExcluderTest {

    private Excluder excluder;
    private Method excludeClassChecksMethod;

    @BeforeEach
    void setUp() throws Exception {
        excluder = new Excluder();
        excludeClassChecksMethod = Excluder.class.getDeclaredMethod("excludeClassChecks", Class.class);
        excludeClassChecksMethod.setAccessible(true);
    }

    @Test
    void excludeClassChecks_VersionIgnored_ReturnsFalse() throws Exception {
        // version == IGNORE_VERSIONS disables version check
        // IGNORE_VERSIONS is -1.0d by default in Excluder.DEFAULT
        // So by default version is -1.0d, so version check skipped
        // disable inner class serialization false by default (serializeInnerClasses == true)
        // so isInnerClass check skipped
        // last isAnonymousOrNonStaticLocal called, let's test with a normal class (this class)
        boolean result = (boolean) excludeClassChecksMethod.invoke(excluder, ExcluderTest.class);
        // ExcluderTest is a normal static top-level class, so isAnonymousOrNonStaticLocal returns false
        assertFalse(result);
    }

    @Test
    void excludeClassChecks_VersionInvalid_ReturnsTrue() throws Exception {
        // Set version to a positive value to enable version check
        excluder = excluder.withVersion(1.0);

        // Create test class with Since annotation with value 2.0 (higher than version 1.0)
        @Since(2.0)
        class Since2 {}

        // since 2.0 > 1.0, isValidVersion should return false, so method returns true
        boolean result = (boolean) excludeClassChecksMethod.invoke(excluder, Since2.class);
        assertTrue(result);
    }

    @Test
    void excludeClassChecks_VersionValid_InnerClassSerializationDisabled_ReturnsTrue() throws Exception {
        excluder = excluder.withVersion(2.0).disableInnerClassSerialization();

        // Inner class to test
        class InnerClass {}

        // version 2.0, inner class serialization disabled, so isInnerClass true => method returns true
        boolean result = (boolean) excludeClassChecksMethod.invoke(excluder, InnerClass.class);
        assertTrue(result);
    }

    @Test
    void excludeClassChecks_VersionValid_InnerClassSerializationEnabled_AnonymousOrNonStaticLocal_ReturnsTrue() throws Exception {
        excluder = excluder.withVersion(2.0);

        // Anonymous class instance
        Object anonymous = new Runnable() {
            @Override public void run() {}
        };

        // anonymous.getClass() is anonymous class, so method returns true
        boolean result = (boolean) excludeClassChecksMethod.invoke(excluder, anonymous.getClass());
        assertTrue(result);
    }

    @Test
    void excludeClassChecks_VersionValid_InnerClassSerializationEnabled_StaticClass_ReturnsFalse() throws Exception {
        excluder = excluder.withVersion(2.0);

        // Static nested class
        class StaticNested {
        }

        // StaticNested is not inner class, and not anonymous or non-static local
        boolean result = (boolean) excludeClassChecksMethod.invoke(excluder, StaticNested.class);
        assertFalse(result);
    }

}
